1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const CURSED_SURCHARGE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT_RATE = 0.2;
16	const LOYALTY_THRESHOLD = 2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
19	const PROCESSING_FEE = 5;
20	const DEDUCTIBLE = 100;
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	};
28	const COMPONENT_INSURANCE_VALUE = 250;
29	
30	interface Item {
31	  type: string;
32	  cursed?: boolean;
33	  enchantment?: number;
34	}
35	
36	function isMainItem(type: string): boolean {
37	  return type in BASE_PREMIUMS;
38	}
39	
40	function isKnownType(type: string): boolean {
41	  return isMainItem(type) || KNOWN_COMPONENT_TYPES.has(type);
42	}
43	
44	function mainItemPremium(items: Item[]): number {
45	  return items
46	    .filter((item) => isMainItem(item.type))
47	    .reduce((sum, item) => sum + itemBasePremium(item), 0);
48	}
49	
50	function componentCounts(items: Item[]): Map<string, number> {
51	  const counts = new Map<string, number>();
52	  for (const item of items) {
53	    if (!isMainItem(item.type)) {
54	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
55	    }
56	  }
57	  return counts;
58	}
59	
60	function componentPremium(items: Item[]): number {
61	  return [...componentCounts(items).values()].reduce(
62	    (total, count) => total + (count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM),
63	    0,
64	  );
65	}
66	
67	function itemBasePremium(item: Item): number {
68	  return BASE_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
69	}
70	
71	function singleItemSurcharge(item: Item): number {
72	  const base = itemBasePremium(item);
73	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
74	    + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
75	}
76	
77	function itemSurcharges(items: Item[]): number {
78	  return items.reduce((sum, item) => sum + singleItemSurcharge(item), 0);
79	}
80	
81	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
82	  const basePremium = mainItemPremium(items) + componentPremium(items);
83	  const surcharges = itemSurcharges(items);
84	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
85	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
86	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
87	  return Math.ceil(basePremium + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
88	}
89	
90	function validateItems(items: Item[]): void {
91	  for (const item of items) {
92	    if (!isKnownType(item.type)) {
93	      throw new Error(`Unknown item type: ${item.type}`);
94	    }
95	  }
96	}
97	
98	function insuranceSum(items: Item[]): number {
99	  return items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? COMPONENT_INSURANCE_VALUE), 0);
100	}
101	
102	function processClaim(
103	  policy: { items: Item[]; remainingCap: number },
104	  damages: Array<{ itemType: string; amount: number }>,
105	): { payout: number; remainingCap: number } {
106	  let totalPayout = 0;
107	  for (const damage of damages) {
108	    const payout = Math.max(0, damage.amount - DEDUCTIBLE);
109	    totalPayout += payout;
110	  }
111	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
112	  policy.remainingCap -= cappedPayout;
113	  return { payout: cappedPayout, remainingCap: policy.remainingCap };
114	}
115	
116	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Item[]; policy?: number; incident?: { cause: string; damages: Array<{ itemType: string; amount: number }> } }> }) {
117	  const policies: Array<{ items: Item[]; remainingCap: number }> = [];
118	  const results = scenario.steps.map((step, index) => {
119	    if (step.op === "quote") {
120	      const items = step.items ?? [];
121	      validateItems(items);
122	      const cap = 2 * insuranceSum(items);
123	      policies.push({ items, remainingCap: cap });
124	      return { premium: computeQuotePremium(items, scenario.customer, index > 0) };
125	    } else {
126	      const policy = policies[step.policy!];
127	      return processClaim(policy, step.incident!.damages);
128	    }
129	  });
130	  return { results };
131	}
